import { eventful } from 'https://cdn.jsdelivr.net/npm/asljs-eventful/+esm';
import { observable } from 'https://cdn.jsdelivr.net/npm/asljs-observable/+esm';
import { bindDataModel } from 'https://cdn.jsdelivr.net/npm/asljs-data-binding/+esm';
import 'https://cdn.jsdelivr.net/npm/asljs-components/+esm';
import { dbOpen, Table } from 'https://cdn.jsdelivr.net/npm/asljs-dali/+esm';
import * as pdfjsLib from 'https://cdn.jsdelivr.net/npm/pdfjs-dist@5.6.205/build/pdf.mjs';

pdfjsLib.GlobalWorkerOptions.workerSrc =
  'https://cdn.jsdelivr.net/npm/pdfjs-dist@5.6.205/build/pdf.worker.mjs';

const BUFFER_WIDTH = 100;
const DB_NAME = 'pdf-text-extractor-db';
const STORE_NAME = 'sessions';
const SAMPLE_MESSAGE = 'Drop a PDF file or click here to choose one. The app maps extracted text into a 100-column virtual text buffer per page.';
const MAX_HISTORY = 8;

let booted = false;

window.addEventListener('error', event => {
  console.error('Window error', event.error || event.message);
});

window.addEventListener('unhandledrejection', event => {
  console.error('Unhandled rejection', event.reason);
});

boot().catch(error => {
  console.error('Boot failed', error);
});

async function boot() {
  if (booted) return;
  booted = true;
  console.log('boot:start');

  const root = document.getElementById('app');
  if (!root) throw new Error('Missing #app root element.');

  const bus = eventful({ name: 'pdf-text-extractor-bus' });
  const state = observable({
    stats: {
      pages: 0,
      characters: 0,
      sessions: 0,
    },
    ui: {
      dragOver: false,
      busy: false,
      dropzoneTitle: 'Drop PDF here',
      dropzoneHint: SAMPLE_MESSAGE,
      status: {
        message: 'Ready for a PDF.',
        error: '',
      },
      loadSample() {
        state.ui.status.message = 'Instructions loaded. Now drop a PDF file.';
        state.ui.status.error = '';
        addLog('Instructions', SAMPLE_MESSAGE, true);
        bus.emit('status', state.ui.status.message);
      },
      clearOutput() {
        state.pages.length = 0;
        state.stats.pages = 0;
        state.stats.characters = 0;
        state.ui.status.message = 'Output cleared.';
        state.ui.status.error = '';
        addLog('Cleared', 'Removed extracted pages from the current view.', false);
        bus.emit('cleared');
      },
    },
    pages: observable([]),
    activity: observable([]),
    history: observable([]),
    selectedSessionId: null,
    lastSessionId: null,
    restoreSession(event, model, element) {
      const sessionId = element?.dataset?.sessionId;
      if (!sessionId) return;
      restoreSessionById(sessionId);
    },
    async clearHistory() {
      if (!sessions?.clear) return;
      await sessions.clear();
      state.history.splice(0, state.history.length);
      state.selectedSessionId = null;
      state.stats.sessions = 0;
      state.ui.status.message = 'Saved session history cleared.';
      state.ui.status.error = '';
      addLog('History cleared', 'Removed saved extraction sessions from IndexedDB.', true);
      bus.emit('status', state.ui.status.message);
    },
  });

  let sessions = null;
  let liveSessions = null;

  try {
    const db = await dbOpen(DB_NAME, [database => {
      if (!database.objectStoreNames.contains(STORE_NAME)) {
        database.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    }]);

    sessions = new Table(STORE_NAME, db, {});

    const refreshHistory = async (logLatest = false) => {
      if (!sessions?.scan) return;
      const records = await sessions.scan(() => true);
      const sorted = [...records].sort((a, b) => (b.createdAt || '').localeCompare(a.createdAt || ''));
      state.history.splice(0, state.history.length, ...sorted.slice(0, MAX_HISTORY).map(record => ({
        id: record.id,
        fileName: record.fileName,
        pageCount: record.pageCount,
        characterCount: record.characterCount,
        createdAt: record.createdAt,
        selected: record.id === state.selectedSessionId,
        summary: `${record.pageCount} page(s) • ${record.characterCount} chars`,
      })));
      state.stats.sessions = records.length;

      const latest = sorted[0];
      if (!logLatest || !latest || latest.id === state.lastSessionId) return;
      state.lastSessionId = latest.id;
      addLog('Saved session', `${latest.fileName} (${latest.pageCount} pages) stored in IndexedDB.`, false);
    };

    await refreshHistory(false);
    sessions.notify({
      add() {
        refreshHistory(true).catch(error => console.warn('History refresh failed', error));
      },
      put() {
        refreshHistory(true).catch(error => console.warn('History refresh failed', error));
      },
      update() {
        refreshHistory(false).catch(error => console.warn('History refresh failed', error));
      },
      delete() {
        refreshHistory(false).catch(error => console.warn('History refresh failed', error));
      },
      clear() {
        refreshHistory(false).catch(error => console.warn('History refresh failed', error));
      },
    });
  } catch (error) {
    console.warn('Persistence unavailable', error);
    state.ui.status.error = 'IndexedDB persistence unavailable in this environment.';
  }

  bus.on('status', message => addLog('Status', message, false));
  bus.on('pdf-loaded', payload => addLog('PDF loaded', `${payload.fileName} with ${payload.pageCount} pages extracted.`, true));
  bus.on('error', message => addLog('Error', message, true));

  bindDataModel(root, state, {});

  const pagesList = document.getElementById('pages-list');
  if (pagesList) {
    pagesList.items = state.pages;
    pagesList.context = state;
  }

  const activityList = document.getElementById('activity-list');
  if (activityList) {
    activityList.items = state.activity;
    activityList.context = state;
  }

  const historyList = document.getElementById('history-list');
  if (historyList) {
    historyList.items = state.history;
    historyList.context = state;
  }

  wireFileInput(state, bus, sessions);
  wireDropzone(state, bus, sessions);

  state.ui.status.message = 'Ready for a PDF. Drag and drop or click the dropzone.';
  addLog('Ready', 'Application booted successfully.', false);

  window.__PDF_TEXT_EXTRACTOR__ = { state, bus, sessions };

  async function restoreSessionById(sessionId) {
    if (!sessions?.getOne) return;
    try {
      const session = await sessions.getOne(sessionId);
      if (!session) {
        state.ui.status.error = 'Saved session not found.';
        bus.emit('error', state.ui.status.error);
        return;
      }

      state.selectedSessionId = session.id;
      for (const item of state.history) {
        item.selected = item.id === session.id;
      }

      state.pages.splice(0, state.pages.length, ...(session.pages || []));
      state.stats.pages = session.pageCount || 0;
      state.stats.characters = session.characterCount || 0;
      state.ui.status.message = `Restored ${session.fileName} from saved history.`;
      state.ui.status.error = '';
      addLog('Session restored', `${session.fileName} loaded from IndexedDB history.`, true);
      bus.emit('status', state.ui.status.message);
    } catch (error) {
      console.error(error);
      state.ui.status.error = 'Failed to restore saved session.';
      bus.emit('error', state.ui.status.error);
    }
  }

  function addLog(title, detail, highlight) {
    state.activity.unshift({
      id: crypto.randomUUID(),
      title,
      detail,
      highlight,
      time: new Date().toLocaleTimeString(),
    });
    if (state.activity.length > 12) {
      state.activity.length = 12;
    }
  }
}

function wireFileInput(state, bus, sessions) {
  const input = document.getElementById('pdf-input');
  if (!input) return;

  input.addEventListener('change', async event => {
    const file = event.target?.files?.[0];
    if (!file) return;
    await handlePdfFile(file, state, bus, sessions);
    input.value = '';
  });
}

function wireDropzone(state, bus, sessions) {
  const dropzone = document.getElementById('dropzone');
  if (!dropzone) return;

  ['dragenter', 'dragover'].forEach(type => {
    dropzone.addEventListener(type, event => {
      event.preventDefault();
      state.ui.dragOver = true;
    });
  });

  ['dragleave', 'dragend'].forEach(type => {
    dropzone.addEventListener(type, () => {
      state.ui.dragOver = false;
    });
  });

  dropzone.addEventListener('drop', async event => {
    event.preventDefault();
    state.ui.dragOver = false;
    const file = event.dataTransfer?.files?.[0];
    if (!file) return;
    await handlePdfFile(file, state, bus, sessions);
  });
}

async function handlePdfFile(file, state, bus, sessions) {
  if (file.type && file.type !== 'application/pdf') {
    state.ui.status.error = 'Please drop a valid PDF file.';
    bus.emit('error', state.ui.status.error);
    return;
  }

  state.ui.busy = true;
  state.ui.status.message = `Reading ${file.name}...`;
  state.ui.status.error = '';
  bus.emit('status', state.ui.status.message);

  try {
    const bytes = await file.arrayBuffer();
    const loadingTask = pdfjsLib.getDocument({ data: bytes });
    const pdf = await loadingTask.promise;
    const pages = [];
    let totalCharacters = 0;

    for (let pageNumber = 1; pageNumber <= pdf.numPages; pageNumber += 1) {
      const page = await pdf.getPage(pageNumber);
      const viewport = page.getViewport({ scale: 1 });
      const textContent = await page.getTextContent();
      const rendered = renderPageToBuffer(textContent.items, viewport.width, viewport.height);
      totalCharacters += rendered.replace(/\n/g, '').length;
      pages.push({
        id: `${file.name}-${pageNumber}`,
        pageNumber,
        summary: `${rendered.length} chars`,
        text: rendered,
      });
    }

    state.pages.splice(0, state.pages.length, ...pages);
    state.stats.pages = pages.length;
    state.stats.characters = totalCharacters;
    state.ui.status.message = `Extracted ${pages.length} page(s) from ${file.name}.`;
    state.ui.status.error = '';

    const session = {
      id: crypto.randomUUID(),
      fileName: file.name,
      pageCount: pages.length,
      characterCount: totalCharacters,
      createdAt: new Date().toISOString(),
      pages,
    };

    if (sessions?.put) {
      await sessions.put(session);
    }
    bus.emit('pdf-loaded', { fileName: file.name, pageCount: pages.length });
  } catch (error) {
    console.error(error);
    state.ui.status.error = error?.message || 'Failed to extract PDF text.';
    bus.emit('error', state.ui.status.error);
  } finally {
    state.ui.busy = false;
  }
}

function renderPageToBuffer(items, pageWidth, pageHeight) {
  const rows = [];
  const rowCount = Math.max(1, Math.ceil((pageHeight / pageWidth) * BUFFER_WIDTH * 1.6));

  for (let i = 0; i < rowCount; i += 1) {
    rows.push(Array(BUFFER_WIDTH).fill(' '));
  }

  for (const item of items) {
    const text = String(item.str || '');
    if (!text.trim()) continue;

    const transform = item.transform || [1, 0, 0, 1, 0, 0];
    const x = Number(transform[4] || 0);
    const y = Number(transform[5] || 0);
    const col = clamp(Math.round((x / Math.max(pageWidth, 1)) * (BUFFER_WIDTH - 1)), 0, BUFFER_WIDTH - 1);
    const row = clamp(Math.round(((pageHeight - y) / Math.max(pageHeight, 1)) * (rowCount - 1)), 0, rowCount - 1);

    for (let i = 0; i < text.length; i += 1) {
      const targetCol = col + i;
      if (targetCol >= BUFFER_WIDTH) break;
      rows[row][targetCol] = text[i];
    }
  }

  return rows
    .map(chars => chars.join('').replace(/\s+$/g, ''))
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trimEnd();
}

function clamp(value, min, max) {
  return Math.min(max, Math.max(min, value));
}

