:root {
  color-scheme: light;
  --bg: #f4f7fb;
  --panel: #ffffff;
  --border: #d8e0ea;
  --text: #1f2937;
  --muted: #5f6b7a;
  --accent: #2563eb;
  --accent-soft: #dbeafe;
  --danger: #b91c1c;
  --shadow: 0 10px 30px rgba(15, 23, 42, 0.08);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: Arial, Helvetica, sans-serif;
  background: var(--bg);
  color: var(--text);
}

.app-shell {
  max-width: 1400px;
  margin: 0 auto;
  padding: 24px;
}

.hero {
  display: flex;
  justify-content: space-between;
  gap: 16px;
  align-items: flex-start;
  margin-bottom: 24px;
}

.hero h1 {
  margin: 0 0 8px;
}

.subtitle {
  margin: 0;
  color: var(--muted);
}

.hero-stats {
  display: flex;
  gap: 12px;
}

.stat-card,
.panel,
.page-card,
.status-card,
.log-entry {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 14px;
  box-shadow: var(--shadow);
}

.stat-card {
  min-width: 110px;
  padding: 14px;
}

.stat-label {
  display: block;
  color: var(--muted);
  font-size: 12px;
  margin-bottom: 6px;
}

.workspace {
  display: grid;
  grid-template-columns: 340px 1fr;
  gap: 20px;
}

.panel {
  padding: 18px;
}

.controls {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.dropzone {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  min-height: 220px;
  border: 2px dashed #93c5fd;
  border-radius: 16px;
  background: #eff6ff;
  text-align: center;
  padding: 20px;
  cursor: pointer;
  transition: 0.2s ease;
}

.dropzone.dragover {
  border-color: var(--accent);
  background: var(--accent-soft);
  transform: scale(1.01);
}

.dropzone.busy {
  opacity: 0.7;
}

.dropzone input {
  display: none;
}

.dropzone-title {
  font-size: 20px;
  font-weight: 700;
  margin-bottom: 8px;
}

.dropzone-hint {
  color: var(--muted);
  line-height: 1.5;
}

.actions {
  display: flex;
  gap: 10px;
}

.compact-actions {
  margin-bottom: 10px;
}

button {
  border: 1px solid var(--border);
  background: white;
  color: var(--text);
  border-radius: 10px;
  padding: 10px 14px;
  cursor: pointer;
}

button.secondary {
  background: #eff6ff;
}

button.danger {
  color: white;
  background: var(--danger);
  border-color: var(--danger);
}

.status-card {
  padding: 14px;
}

.status-card h2,
.output-header h2 {
  margin-top: 0;
}

.status-line,
.error-line,
.empty-state,
.empty-output p,
.output-header p,
.log-entry p {
  margin-bottom: 0;
}

.error-line {
  color: var(--danger);
  min-height: 1.2em;
}

.log-list,
.pages-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.log-entry {
  padding: 12px;
}

.history-entry {
  width: 100%;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.history-entry.selected {
  border-color: var(--accent);
  background: var(--accent-soft);
}

.log-entry.highlight {
  border-color: #93c5fd;
}

.log-entry-top {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  font-size: 12px;
  color: var(--muted);
}

.output-panel {
  min-width: 0;
}

.output-header {
  margin-bottom: 16px;
}

.page-card {
  padding: 16px;
}

.page-card-header {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: baseline;
  margin-bottom: 12px;
}

.page-card-header h3 {
  margin: 0;
}

.page-text {
  margin: 0;
  white-space: pre-wrap;
  font-family: "Courier New", Courier, monospace;
  font-size: 8pt;
  line-height: 1.2;
  overflow: auto;
  background: #f8fafc;
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 12px;
}

.empty-output {
  border: 1px dashed var(--border);
  border-radius: 14px;
  padding: 24px;
  text-align: center;
  background: #f8fafc;
}

@media (max-width: 980px) {
  .hero,
  .workspace {
    grid-template-columns: 1fr;
    display: grid;
  }

  .hero-stats {
    flex-wrap: wrap;
  }
}
